INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd8941770-cf9d-498c-974e-a902400a7646',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGPU — Leveraging DirectX D3D12 and DXIL Bytecode for Cross-Platform Gaming$escape$,
  $escape$WebGPU's native integration with DirectX allows for seamless execution of D3D12 commands and DXIL bytecode. By utilizing the `gpu::Device` interface, developers can create a device that supports DirectX-specific features, enabling the creation of high-performance, Windows-native, and Xbox-compatible games. The `gpu::CommandEncoder` can be used to record commands that are compatible with D3D12, while the `gpu::ShaderModule` can be used to create shaders from DXIL bytecode. This enables developers to leverage the power of DirectX while targeting multiple platforms with WebGPU.$escape$,
  $escape$const device = await navigator.gpu.requestDevice({ requiredFeatures: ['dx12'] });
const commandEncoder = device.createCommandEncoder();
const shaderModule = device.createShaderModule({ code: dxilBytecode });$escape$,
  $escape$javascript$escape$,
