INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f0d4f04f-e37c-442f-9272-dc64fadf128a',
  '00000000-0000-0000-0000-000000000001',
  $escape$webgpu: Graphics Pipeline Essentials$escape$,
  $escape$The webgpu graphics pipeline consists of four stages: vertex processing, rasterization, fragment shading, and output merger. Vertex processing occurs when the `CommandEncoder` submits a `PipelineState` descriptor containing a `VertexStage` to the GPU. This stage is responsible for transforming vertices from object space to clip space. Rasterization occurs when the GPU executes a `RasterizationState` descriptor, which determines how primitives are interpolated and culled. Fragment shading occurs when the GPU executes a `FragmentStage` descriptor, which computes the final color of each pixel. The output merger stage combines the final pixel colors into a final image. Each stage has its own set of resources and buffers that must be managed properly.$escape$,
  $escape$const encoder = device.createCommandEncoder();
const pipeline = device.createRenderPipeline(
  {
    vertex: {
      module: device.createShaderModule({
        code: '#version 450 core
          layout(location = 0) in vec3 position;
          void main() {
            gl_Position = vec4(position, 1.0);
          }
        ',
      }),
      entryPoint: 'main',
    },
  },
);
encoder.copyBufferToBuffer(
  pipeline.getBindGroupLayoutEntry('vertexBuffer'),
  0,
  device.getBuffer('vertexBuffer'),
  0,
);
$escape$,
